[
  {
    "text": "DreamX-World 1.0 supports camera navigation, revisits to previously observed regions, and promptable events across photorealistic, game-style, and stylized domains.",
    "topic": "DreamX-World capabilities"
  },
  {
    "text": "The data engine of DreamX-World 1.0 combines camera-accurate Unreal Engine rendering, action-rich gameplay recordings, and real-world videos with recovered camera geometry.",
    "topic": "DreamX-World data engine"
  },
  {
    "text": "E-PRoPE, a lightweight variant of projective positional encoding, is introduced for camera control in DreamX-World 1.0, retaining projective camera geometry while applying camera-aware attention to spatially reduced tokens.",
    "topic": "E-PRoPE in DreamX-World"
  },
  {
    "text": "DreamX-World 1.0 achieves a camera-control score of 73.75 and an overall score of 84.76 on a 5-second basic evaluation, outperforming HY-WorldPlay 1.5 and LingBot-World.",
    "topic": "DreamX-World evaluation scores"
  },
  {
    "text": "With mixed-precision DiT execution, residual reuse, 75%-pruned VAE decoding, and asynchronous pipeline parallelism, DreamX-World 1.0 reaches up to 16 FPS on eight RTX 5090 GPUs.",
    "topic": "DreamX-World performance"
  }
]
